import React from 'react';
import './Title.css';

const Title = ({title}) => {
    const currentScreenTitle = title.toLowerCase();
    const currentScreenTitleArray = currentScreenTitle.split(' ');
    const currentScreentTitleClass = currentScreenTitleArray.join('-');
    return (
        <div className="title-contents">
            <div className={`${currentScreentTitleClass}-title screen-title`}>
                <h1>{title}</h1>
            </div>
        </div>
    )
}

export default Title;
