import React from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faEnvelope } from '@fortawesome/free-solid-svg-icons';
import './HeaderContent.css';

const HeaderContent = () => {
    const currentUrlAddress = window.location.href;
    return (
        <div className="main-header-container">
            <div className="header-logo">
                <a href={currentUrlAddress}><img className="main-logo" src={require('../../assets/logo/logo.png')} alt="header-logo"/></a>
                <h6>CJY Studio</h6>
            </div>
            <div className="header-contact-email">
                <a href="mailto:zonezoneyang@gmail.com"><FontAwesomeIcon className="font-awsome-header-contact-email" icon={faEnvelope} size="3x" color="#ff533d" /></a>
            </div>
        </div>
    )
}

export default HeaderContent;
