import React, { useState, Fragment } from 'react';
import { CSSTransition } from 'react-transition-group';
import './Button.css';

const Button = ({ btnDatas, onClick, parentContainer }) => {
    const previousClasses = ['about-btn', 'skills-btn', 'projects-btn'];
    const [classExist, setClassExist] = useState(false);
    // const [currentClickedBtn, setCurrentClickedBtn] = useState([{ clicked: 'noBorder' }, { clicked: 'noBorder' }, { clicked: 'noBorder' }]);
    const [btnClickedNum,setBtnClickedNum] = useState(null);
    const [startEnterDoneClass, setStartEnterDoneClass] = useState(false);


    const handleStateChange = (e) => {
        e.persist();
        e.stopPropagation();
        e.preventDefault();
        console.log(e);
        // console.log(e._targetInst.key);
        setBtnClickedNum(parseInt(e._targetInst.key));

        // setTimeout(,4000);
        // changeBorderColor(e.target.innerText)
        onClick(e.target.classList[1]);
        adjButtonPosition(e.target);
        // setTimeout(() => {
            setStartEnterDoneClass(true);
        // }, 2000);
    }

    const adjButtonPosition = (buttonEl) => {
        previousClasses.map((previousClass) => {
            const containClass = buttonEl.classList.contains(previousClass);
            if (containClass) {
                setClassExist(true);
            }
            return '';
        });
    }

    // const changeBorderColor = (currClickedBtn) => {
    //     const currClickedBtnLowerCase = currClickedBtn.toLowerCase();
    //     if (currClickedBtnLowerCase === 'about') {
    //         setCurrentClickedBtn([{ clicked: 'aboutBorder' }, { clicked: 'noBorder' }, { clicked: 'noBorder' }]);
    //     } else if (currClickedBtnLowerCase === 'skills') {
    //         setCurrentClickedBtn([{ clicked: 'noBorder' }, { clicked: 'skillsBorder' }, { clicked: 'noBorder' }]);
    //     } else if (currClickedBtnLowerCase === 'projects') {
    //         setCurrentClickedBtn([{ clicked: 'noBorder' }, { clicked: 'noBorder' }, { clicked: 'projectsBorder' }]);
    //     }
    // }

    return (
        <Fragment>
            {btnDatas.map((btnData, i) => {

                return (<CSSTransition key={i} in={classExist} timeout={1200} classNames={btnData.btnClass}>

                    <button
                        key={i}
                        className={classExist ? `${btnData.btnClass}-reposition ${btnData.btn} main-btn ${btnClickedNum === i ? 'borderColor' : ''} ${startEnterDoneClass ? btnData.btnClass + '-enter-done' : ' '}` : `${btnData.btnClass} ${btnData.btn} main-btn original-btn`}
                        onClick={handleStateChange}
                    >{btnData.btnName}
                    </button>

                </CSSTransition>)

            })}
        </Fragment>
    )
}

export default Button;



