import React, { useState, useEffect } from 'react';
import './App.css';
import Header from '../header/Header';
import Home from '../home/Home';



const App = () => {

  const [mainButtonClicked, setMainButtonClicked] = useState(false);




  const [windowWidth, setWindowWidth] = useState(null);

  const [mobileBreakPoint, setMobileBreakPoint] = useState(false);

  useEffect(()=>{
    console.log(mainButtonClicked);
    // if(mobileBreakPoint && mainButtonClicked){
    //   document.body.style.overflow = "auto";
    // }
  });



  useEffect(() => {
    const windowWidthFirstCheck = setTimeout(() => {
      currentWindowWidth();
    }, 100);
    window.addEventListener("resize", currentWindowWidth);
    return () => {
      window.removeEventListener("resize", currentWindowWidth);
      clearTimeout(windowWidthFirstCheck);
    }
  }, [windowWidth]);

  const currentWindowWidth = () => {
    const mobileBreakPointWidth = window.innerWidth <= 1000;
    const disableViewResolution = (window.innerWidth >= 2560 || window.innerWidth <= 350);
    setWindowWidth(disableViewResolution);
    setMobileBreakPoint(mobileBreakPointWidth);
    if(disableViewResolution){
      setMainButtonClicked(false);
    }else{
      return '';
    }
  }




  const checkMainBtnClicked = (btnClicked) => {
    if(mainButtonClicked){
      return ' ';
    }else{
      setMainButtonClicked(btnClicked);
      // console.log(btnClicked);
    }
  }

  const limitBrowserWidth = () => {
    if (windowWidth) {
      // Create another component here for showing the message if the resolution is over 2k and is below 350px
      return (<div>{`The browser is a 2k and above monitor: ${windowWidth}`}</div>)
    } else {
      return (
        <React.Fragment>
          <Header />
          <Home btnClicked={checkMainBtnClicked} />
        </React.Fragment>

      )
    }
  }
  return (
    <div className={(mainButtonClicked && mobileBreakPoint && !windowWidth) ? `App mobile-app` : `App`}>
      {limitBrowserWidth()}
    </div>
  );
}

export default App;
